skus = set()

for row in data:
    for key in row.keys():
        if key.startswith("SKU_") and key.endswith("_g"):
            sku = key.replace("SKU_", "").replace("_g", "")
            skus.add(sku)

skus = sorted(list(skus))

# ----------------------------------
# FILTER BY MONTH (if selected)
# ----------------------------------
if selected_dt:

    sel_year  = system.date.getYear(selected_dt)
    sel_month = system.date.getMonth(selected_dt)

    filtered = []

    for row in data:
        d = row["day_dt"]

        if (
            system.date.getYear(d) == sel_year and
            system.date.getMonth(d) == sel_month
        ):
            filtered.append(row)

else:
    filtered = list(data)

# ----------------------------------
# ENSURE ALL SKU COLUMNS EXIST
# (important for table consistency)
# ----------------------------------
result = []

for row in filtered:

    new_row = dict(row)  # shallow copy

    for sku in skus:
        prefix = "SKU_" + sku

        if prefix + "_g" not in new_row:
            new_row[prefix + "_g"] = {"value": None}

        if prefix + "_pct" not in new_row:
            new_row[prefix + "_pct"] = {"value": None}

        if prefix + "_dol" not in new_row:
            new_row[prefix + "_dol"] = {"value": None}

    # totals safety
    if "TOTAL_g" not in new_row:
        new_row["TOTAL_g"] = {"value": None}

    if "TOTAL_pct" not in new_row:
        new_row["TOTAL_pct"] = {"value": None}

    if "TOTAL_dol" not in new_row:
        new_row["TOTAL_dol"] = {"value": None}

    result.append(new_row)

return result

